const items = $input.all();
return items
  .filter(item => item.json.userId <= 3)
  .map(item => ({
    json: {
      id: item.json.id,
      userId: item.json.userId,
      titre: item.json.title.substring(0, 50),
      longueur_body: item.json.body.length,
      traite_le: new Date().toISOString()
    }
  }));

const items = $input.all();
const stats = {
  total: items.length,
  par_user: {},
  longueur_moyenne: Math.round(items.reduce((acc, i) => acc + i.json.longueur_body, 0) / items.length)
};
items.forEach(i => {
  const uid = 'user_' + i.json.userId;
  stats.par_user[uid] = (stats.par_user[uid] || 0) + 1;
});
return [{ json: stats }];
